import "./RecipeDetails.css";
import { useEffect, useState } from "react";
import axios from "axios";
import { useParams, useNavigate } from "react-router-dom";
import UserNavbar from "./UserNavbar";

export default function RecipeDetails() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [recipe, setRecipe] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem("token");

    if (!token) {
      alert("Please login first ❌");
      navigate("/login");
      return;
    }

    axios
      .get(`http://127.0.0.1:8000/api/recipes/${id}/`, {
        headers: {
          Authorization: `Token ${token}`,
        },
      })
      .then((res) => {
        setRecipe({
          ...res.data,

          // FIX IMAGE PATH
          image: res.data.image
            ? `http://127.0.0.1:8000${res.data.image}`
            : "/default-food.jpg",

          // FIX UI EXPECTATION
          author: res.data.created_by || "Unknown",
          views: res.data.view_count || 0,
        });

        setLoading(false);
      })
      .catch((err) => {
        console.error("Recipe detail error:", err);
        alert("Failed to load recipe ❌");
        setLoading(false);
      });
  }, [id, navigate]);

  if (loading) return <h2>Loading...</h2>;
  if (!recipe) return null;

  return (
    <>
      <UserNavbar />

      <div className="recipe-details">
        <img src={recipe.image} alt={recipe.title} />

        <h2>{recipe.title}</h2>
        <p>👤 {recipe.author}</p>
        <p>👁 {recipe.views} views</p>

        <h3>Ingredients</h3>
        <p>{recipe.ingredients}</p>

        <h3>Steps</h3>
        <p>{recipe.steps}</p>

        <p>⏱ {recipe.cooking_time} minutes</p>
        <p>🔥 Difficulty: {recipe.difficulty}</p>
      </div>
    </>
  );
}
